const { event, data } = context;
if (event !== 'ticket.resolved') return;
const messages = data.messages || [];
if (!messages.length) return;
const cfg = cliaas.config;
cliaas.log.info(`Generating AI summary for ticket ${data.ticketId} (${messages.length} messages, model: ${cfg.model || 'gpt-4o-mini'})`);
